WITH prod_rev AS (
  SELECT product, SUM(revenue) AS total_rev
  FROM sales
  GROUP BY product
), avg_rev AS (
  SELECT AVG(total_rev) AS avg_rev FROM prod_rev
)
SELECT product
FROM prod_rev, avg_rev
WHERE prod_rev.total_rev > avg_rev.avg_rev;

SELECT quarter, product, revenue FROM (
  SELECT quarter, product, SUM(revenue) AS revenue, RANK() OVER (PARTITION BY quarter ORDER BY SUM(revenue) DESC) AS rnk
  FROM sales
  GROUP BY quarter, product
) sub
WHERE rnk = 1;

SELECT SUM(sales.revenue) - COALESCE(SUM(returns.amount), 0) AS net_revenue
FROM sales
LEFT JOIN returns ON sales.sale_id = returns.sale_id;

SELECT product, SUM(revenue) AS total_revenue
FROM sales
GROUP BY product
HAVING SUM(revenue) > (
   SELECT AVG(product_rev) FROM (
      SELECT SUM(revenue) AS product_rev
      FROM sales
      GROUP BY product
   )
);

SELECT (SUM(sales.revenue) - COALESCE(SUM(returns.amount), 0)) AS net_revenue
FROM sales
LEFT JOIN returns ON sales.sale_id = returns.sale_id;

SELECT product, SUM(revenue) AS total_revenue
FROM sales
GROUP BY product
HAVING total_revenue > (
    SELECT AVG(product_rev) FROM (
        SELECT SUM(revenue) AS product_rev
        FROM sales
        GROUP BY product
    ) sub
);

SELECT SUM(revenue) - COALESCE(SUM(r.amount), 0) AS net_revenue
FROM sales s
LEFT JOIN returns r ON s.sale_id = r.sale_id;
